  ('judicial-57112235-moex-00696', 'judicial-57112235', 'judicial-57112235-moex-110-cc138910', 'sub-judicial-57112235-02', NULL, 'single_choice', '涂爾幹（EmileDurkheim）是法國著名的社會學家，對於犯罪學領域的最大貢獻則是其所提出之無 規範理論（社會亂迷理論，SocialAnomieTheory）。有關涂爾幹及其理論之敘述，下列何者正確？', '["社會唯有物質因素才能維繫人們成為一個團結、聚合的整體", "犯罪是一種不正常、病態的社會現象", "都市化的現代社會，展現一種機械式結合（MechanicalSolidarity）的社會特質", "社會要提供明確的規範來約束人們的行為，否則就會無法控制人們的需要和慾望"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "603b48f24109", "answer_pdf_sha1": "9e5d7a84b2b0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪學概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
